const body = $input.first().json.body;

const mensagem = body.mensagem || '';
const sessionId = body.sessionId || null;
const modulo = body.modulo || {};
const organizacao = body.organizacao || {};
const usuario = body.usuario || {};
const apiKey = body.apiKey || '';
const imagens = body.imagens || [];
const historico = body.historico || [];

const historicoFormatado = historico
  .map(h => `${h.remetente === 'usuario' ? 'Usuário' : 'Assistente'}: ${h.texto}`)
  .join('\n');

const contextoSistema = [
  `Módulo atual: ${modulo.nome || 'Não identificado'}`,
  `Descrição do módulo: ${modulo.descricao || 'N/A'}`,
  `Rota: ${modulo.rota || 'N/A'}`,
  `Organização: ${organizacao.nome || 'N/A'} (ID: ${organizacao.id || 'N/A'})`,
  `Tenant ID: ${organizacao.tenantId || 'N/A'}`,
  `Usuário: ${usuario.nome || 'N/A'} (${usuario.email || 'N/A'})`,
  `Role: ${usuario.role || 'N/A'}`,
].join('\n');

return [{
  json: {
    sessionId,
    chatInput: mensagem,
    mensagem,
    contextoSistema,
    historicoFormatado,
    modulo,
    organizacao,
    usuario,
    imagens,
    apiKey
  }
}];

const items = $input.all();
const dados = $('Processar Dados').first().json;

// Verifica se a query do Postgres retornou uma sessão válida
const hasSession = items.length > 0 && items[0].json && items[0].json.id;

let sessionId;
let modo;
let tentativas_falhas;
let isNew = false;

if (hasSession) {
  const sessao = items[0].json;
  sessionId = sessao.id;
  modo = sessao.modo || 'ia';
  tentativas_falhas = sessao.tentativas_falhas || 0;
} else {
  // Usa o sessionId que o cliente enviou
  sessionId = dados.sessionId;
  if (!sessionId) {
    sessionId = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
  }
  modo = 'ia';
  tentativas_falhas = 0;
  isNew = true;
}

return [{
  json: {
    sessionId,
    modo,
    tentativas_falhas,
    isNew,
    chatInput: dados.chatInput,
    mensagem: dados.mensagem,
    contextoSistema: dados.contextoSistema,
    historicoFormatado: dados.historicoFormatado
  }
}];

// Prepara os dados para alimentar o Agente IA
const sessao = $('Criar ou Reutilizar Sessao').first().json;
const dados = $('Processar Dados').first().json;

return [{
  json: {
    sessionId: sessao.sessionId,
    chatInput: dados.chatInput,
    contextoSistema: dados.contextoSistema,
    historicoFormatado: dados.historicoFormatado
  }
}];

const output = $input.first().json;
const respostaIA = output.output || output.text || output.response || 'Desculpe, não consegui gerar uma resposta.';
const sessionId = $('Criar ou Reutilizar Sessao').first().json.sessionId;
const mensagemCliente = $('Processar Dados').first().json.mensagem || '';
let tentativas_falhas = $('Criar ou Reutilizar Sessao').first().json.tentativas_falhas || 0;

// 1. Verifica se o CLIENTE pediu transferência diretamente
const keywordsClientePedeTransferencia = [
  'quero ser transferido',
  'quero falar com humano',
  'quero falar com uma pessoa',
  'quero falar com atendente',
  'transferir para humano',
  'transferir para atendente',
  'falar com suporte',
  'falar com alguém',
  'falar com alguem',
  'atendente humano',
  'pessoa real',
  'quero um humano',
  'preciso de um humano',
  'me transfere',
  'me transfira',
  'transferência',
  'transferencia'
];

const clientePediuTransferencia = keywordsClientePedeTransferencia.some(
  kw => mensagemCliente.toLowerCase().includes(kw)
);

// 2. Verifica se a IA está indicando que vai transferir
const keywordsIATransfere = [
  'encaminhando sua solicitação',
  'encaminhando para',
  'transferindo para',
  'vou transferir',
  'será transferido',
  'especialista de suporte',
  'atendente humano irá',
  'vou encaminhar'
];

const iaIndicouTransferencia = keywordsIATransfere.some(
  kw => respostaIA.toLowerCase().includes(kw)
);

// 3. Transferência imediata se o cliente pediu ou a IA indicou
const transferenciaImediata = clientePediuTransferencia || iaIndicouTransferencia;

// 4. Verifica se a IA falhou (não conseguiu resolver)
const keywordsFalha = [
  'não consegui',
  'não sei',
  'não encontrei',
  'encaminhar para o suporte',
  'suporte humano',
  'não tenho informação',
  'conteúdo não localizado',
  'não possuo informações',
  'não tenho como ajudar'
];

const falhou = keywordsFalha.some(kw => respostaIA.toLowerCase().includes(kw));
if (falhou) tentativas_falhas += 1;

// Transfere: imediatamente se pediu, ou após 3 falhas
const transferido = transferenciaImediata || tentativas_falhas >= 3;

return [{
  json: {
    respostaIA,
    sessionId,
    tentativas_falhas,
    transferido,
    falhou,
    transferenciaImediata
  }
}];

